#include <pybind11/pybind11.h> #include <pybind11/stl.h> #include <pybind11/numpy.h> #include "true_rft_engine.cpp" namespace py = pybind11; // Python wrapper for True RFT Engine class PyTrueRFTEngine { private: std::unique_ptr<TrueRFTEngine> engine; public: explicit PyTrueRFTEngine(int dimension) { engine = std::make_unique<TrueRFTEngine>(dimension); } py::array_t<std::complex<double>> symbolic_oscillate_wave( py::array_t<std::complex<double>> quantum_state, double frequency) { auto buf = quantum_state.request(); if (buf.ndim != 1) { throw std::runtime_error("Input array must be 1-dimensional"); } int size = buf.shape[0]; auto* ptr = static_cast<std::complex<double>*>(buf.ptr); // Convert to std::vector std::vector<std::complex<double>> state_vec(ptr, ptr + size); // Process with RFT engine auto result = engine->symbolic_oscillate_wave(state_vec, frequency); // Convert back to numpy array auto output = py::array_t<std::complex<double>>(size); auto output_buf = output.request(); auto* output_ptr = static_cast<std::complex<double>*>(output_buf.ptr); std::copy(result.begin(), result.end(), output_ptr); return output; } py::array_t<std::complex<double>> process_quantum_block( py::array_t<std::complex<double>> quantum_state, double frequency, int block_id) { auto buf = quantum_state.request(); if (buf.ndim != 1) { throw std::runtime_error("Input array must be 1-dimensional"); } int size = buf.shape[0]; auto* ptr = static_cast<std::complex<double>*>(buf.ptr); // Convert to std::vector std::vector<std::complex<double>> state_vec(ptr, ptr + size); // Process with RFT engine auto result = engine->process_quantum_block(state_vec, frequency, block_id); // Convert back to numpy array auto output = py::array_t<std::complex<double>>(size); auto output_buf = output.request(); auto* output_ptr = static_cast<std::complex<double>*>(output_buf.ptr); std::copy(result.begin(), result.end(), output_ptr); return output; } py::array_t<std::complex<double>> get_resonance_kernel() { const auto& kernel = engine->get_resonance_kernel(); int dim = engine->get_dimension(); auto output = py::array_t<std::complex<double>>({dim, dim}); auto buf = output.request(); auto* ptr = static_cast<std::complex<double>*>(buf.ptr); for (int i = 0; i < dim; i++) { for (int j = 0; j < dim; j++) { ptr[i * dim + j] = kernel[i][j]; } } return output; } py::array_t<std::complex<double>> get_rft_basis() { const auto& basis = engine->get_rft_basis(); int dim = engine->get_dimension(); auto output = py::array_t<std::complex<double>>({dim, dim}); auto buf = output.request(); auto* ptr = static_cast<std::complex<double>*>(buf.ptr); for (int i = 0; i < dim; i++) { for (int j = 0; j < dim; j++) { ptr[i * dim + j] = basis[i][j]; } } return output; } py::array_t<double> get_golden_weights() { const auto& weights = engine->get_golden_weights(); int dim = engine->get_dimension(); auto output = py::array_t<double>(dim); auto buf = output.request(); auto* ptr = static_cast<double*>(buf.ptr); std::copy(weights.begin(), weights.end(), ptr); return output; } double verify_kernel_hermiticity() { return engine->verify_kernel_hermiticity(); } double verify_basis_orthogonality() { return engine->verify_basis_orthogonality(); } int get_dimension() { return engine->get_dimension(); } bool is_kernel_computed() { return engine->is_kernel_computed(); } }; PYBIND11_MODULE(true_rft_engine_bindings, m) { m.doc() = "True RFT Engine - Symbolic Resonance Kernel for Quantum Simulation"; py::class_<PyTrueRFTEngine>(m, "TrueRFTEngine") .def(py::init<int>(), "Initialize True RFT Engine with given dimension") .def("symbolic_oscillate_wave", &PyTrueRFTEngine::symbolic_oscillate_wave, "Oscillate quantum state as symbolic waves in Hilbert space") .def("process_quantum_block", &PyTrueRFTEngine::process_quantum_block, "Process quantum state block with symbolic resonance") .def("get_resonance_kernel", &PyTrueRFTEngine::get_resonance_kernel, "Get the computed resonance kernel matrix") .def("get_rft_basis", &PyTrueRFTEngine::get_rft_basis, "Get the RFT basis matrix") .def("get_golden_weights", &PyTrueRFTEngine::get_golden_weights, "Get the golden ratio weights") .def("verify_kernel_hermiticity", &PyTrueRFTEngine::verify_kernel_hermiticity, "Verify that the resonance kernel is Hermitian") .def("verify_basis_orthogonality", &PyTrueRFTEngine::verify_basis_orthogonality, "Verify that the RFT basis is orthogonal") .def("get_dimension", &PyTrueRFTEngine::get_dimension, "Get the dimension of the RFT space") .def("is_kernel_computed", &PyTrueRFTEngine::is_kernel_computed, "Check if the RFT kernel has been computed"); } 